export async function fetchProductDetails(id: string) {
  const res = await axios.get(`https://api.example.com/products/${id}`);
  return res.data;
}

export async function createProduct(data: any) {
  const res = await axios.post('https://api.example.com/products', data);
  return res.data;
}

export async function updateProduct(id: string, data: any) {
  const res = await axios.put(`https://api.example.com/products/${id}`, data, {
    headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
  });
  return res.data;
}
